def process_file(filepath):
    """Process a single file, replacing all emoji entities with SVGs."""
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    original = content

    # Sort keys by length (longest first) to avoid partial matches
    sorted_keys = sorted(SVGS.keys(), key=len, reverse=True)

    for emoji, svg in sorted(SVGS.items(), key=lambda x: len(x[0]), reverse=True):
        content = content.replace(emoji, svg)

    if content != original:
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(content)
        return True
    return False

def main():
    base = '/Users/juliocesarmacbookblack/ktana-prototype'
    html_files = []
    for root, dirs, files in os.walk(base):
        for f in files:
            if f.endswith('.html'):
                html_files.append(os.path.join(root, f))

    modified = 0
    for filepath in sorted(html_files):
        if process_file(filepath):
            modified += 1
            print(f"  [MODIFIED] {filepath.replace(base + '/', '')}")
        else:
            # Check if file had emojis that weren't replaced
            with open(filepath, 'r', encoding='utf-8') as f:
                content = f.read()
            import re
            remaining = re.findall(r'&#x[0-9A-Fa-f]+;', content)
            if remaining:
                # Filter out &#xFE0F; as standalone (it's a variation selector, may be leftover)
                remaining = [e for e in remaining if e != '&#xFE0F;']
                if remaining:
                    print(f"  [SKIPPED] {filepath.replace(base + '/', '')} - has unmatched: {set(remaining)}")

    print(f"\nTotal files modified: {modified}")

if __name__ == '__main__':
    main()
